// Home.jsx (ANDROID FRIENDLY)
import React from "react";
import "./Home.css";

export default function Home() {
  return (
    <div className="dash-wrapper" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', minHeight: '100vh', background: '#f7fafc' }}>
      {/* LOGO */}
      <img
        src="/prasa-logo.png"
        alt="PRASA Logo"
        style={{ height: 80, width: 80, objectFit: 'contain', background: '#fff', borderRadius: 16, marginBottom: 16, marginTop: 8 }}
      />
      {/* COMPANY NAME */}
      <span style={{ fontSize: 28, fontWeight: 700, color: '#0f9d58', letterSpacing: 1, marginBottom: 8 }}>PRASA Infocom & Power Solutions Pvt. Ltd.</span>
      {/* Welcome line */}
      <div style={{ fontSize: 20, color: '#222', marginBottom: 32, fontWeight: 500, marginTop: 8 }}>
        Welcome to PRASA Employee Portal
      </div>
      {/* Profile and Settings menu boxes styled like dashboard */}
      <div style={{ display: 'flex', gap: 32 }}>
        <a href="/profile" style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', textDecoration: 'none', transition: 'border 0.2s, box-shadow 0.2s' }}>
          Profile
        </a>
        <a href="/settings" style={{ minWidth: 120, minHeight: 70, background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px rgba(0,0,0,0.08)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', padding: '18px 24px', fontWeight: 600, fontSize: 18, color: '#0f9d58', border: '2px solid #eaf8f0', textDecoration: 'none', transition: 'border 0.2s, box-shadow 0.2s' }}>
          Settings
        </a>
      </div>
    </div>
  );
}
